-- Clean up (order matters for FK references, though SQLite doesn't enforce by default)
DELETE FROM localized_texts WHERE entity_id LIKE 'd0070000%';
DELETE FROM localized_texts WHERE entity_id LIKE 'd0030000-0000-4000-8000-00000000003%';
DELETE FROM localized_texts WHERE entity_id LIKE 'd0040000-0000-4000-8000-0000000002%';
DELETE FROM question_options WHERE question_id LIKE 'd0030000-0000-4000-8000-00000000003%';
DELETE FROM questions WHERE survey_id IN (
    'd0020000-0000-4000-8000-000000000010',
    'd0020000-0000-4000-8000-000000000011',
    'd0020000-0000-4000-8000-000000000012',
    'd0020000-0000-4000-8000-000000000013'
);
DELETE FROM surveys WHERE id IN (
    'd0020000-0000-4000-8000-000000000010',
    'd0020000-0000-4000-8000-000000000011',
    'd0020000-0000-4000-8000-000000000012',
    'd0020000-0000-4000-8000-000000000013'
);
DELETE FROM video_views WHERE video_id LIKE 'd0070000%';
DELETE FROM advertiser_videos WHERE id LIKE 'd0070000%';
DELETE FROM advertisers WHERE id IN (
    'd0060000-0000-4000-8000-000000000001',
    'd0060000-0000-4000-8000-000000000002'
);

